/**
 * Fix SCT Likert Polarity Inversions using gpt-4o-mini
 * 
 * Some SCTs generated by the factory have inverted Likert votes
 * (Rationale says hypothesis is wrong, but votes say +2 instead of -2).
 * This script re-evaluates the true polarity of all 1,000 SCTs and flips 
 * the votes securely if they contradict the rationale.
 */
import { readFileSync, writeFileSync, renameSync } from 'fs';
import { join } from 'path';

const COMPILED_PATH = join(import.meta.dirname, 'output', 'compiled_cases.json');
const FRONTEND_PATH = join(import.meta.dirname, '..', 'public', 'data', 'compiled_cases.json');

const cases = JSON.parse(readFileSync(COMPILED_PATH, 'utf-8'));
const scts = cases.filter(c => c.q_type === 'SCT');

console.log(`Starting Polarity Fix for ${scts.length} SCT cases...`);

async function evaluateDirection(hypothesis, newInfo, rationale) {
  const prompt = `
You are evaluating a Script Concordance Test (SCT).
Hypothesis: "${hypothesis}"
New Information: "${newInfo}"
Rationale given: "${rationale}"

Based on the rationale, does the new information SUPPORT (make more likely) or REJECT (make less likely / prove wrong) the initial hypothesis?
Respond strictly with a single word: SUPPORT or REJECT.
`;

  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${process.env.OPENAI_API_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [{ role: 'user', content: prompt }],
        temperature: 0,
        max_tokens: 10
      })
    });
    
    const data = await res.json();
    if (data.error) {
       console.error('OpenAI API Error:', data.error.message);
       await new Promise(r => setTimeout(r, 2000));
       return null;
    }
    return data.choices[0].message.content.trim().toUpperCase();
  } catch (err) {
    console.error('Fetch Error:', err.message);
    return null;
  }
}

// Simple concurrency limiter
async function asyncPool(poolLimit, array, iteratorFn) {
  const ret = [];
  const executing = [];
  for (const item of array) {
    const p = Promise.resolve().then(() => iteratorFn(item));
    ret.push(p);
    if (poolLimit <= array.length) {
      const e = p.then(() => executing.splice(executing.indexOf(e), 1));
      executing.push(e);
      if (executing.length >= poolLimit) {
        await Promise.race(executing);
      }
    }
  }
  return Promise.all(ret);
}

let flippedCount = 0;
let errors = 0;

async function processCase(c) {
  const hypothesis = c.hypothesis || '';
  const prompt = c.prompt || ''; // where "jika anda berpikir / lalu menemukan" is stored
  const rationale = c.rationale?.correct || '';
  
  // Find current voting peak
  let maxVote = -1;
  let peakVal = 0; // -2, -1, 0, 1, 2
  for (const opt of c.options) {
    if (opt.sct_panel_votes > maxVote) {
      maxVote = opt.sct_panel_votes;
      peakVal = parseInt(opt.id, 10);
    }
  }
  
  // If peak is 0, polarity is neutral, skip
  if (peakVal === 0) return;
  
  let trueDirection = null;
  for(let attempt=0; attempt<3; attempt++) {
      trueDirection = await evaluateDirection(hypothesis, prompt, rationale);
      if (trueDirection) break;
  }
  
  if (!trueDirection) {
    errors++;
    return;
  }
  
  const currentPolarity = peakVal > 0 ? 'SUPPORT' : 'REJECT';
  
  if (trueDirection !== currentPolarity && (trueDirection === 'SUPPORT' || trueDirection === 'REJECT')) {
    // INVERSION DETECTED!
    flippedCount++;
    console.log(`[FLIP] Case ${c._id}: True=${trueDirection}, Peak=${peakVal}`);
    
    // We symmetrically flip the sct_panel_votes array
    // e.g., [-2, -1, 0, 1, 2] -> index 0 and 4 swap, 1 and 3 swap
    const votesArr = c.options.map(o => o.sct_panel_votes);
    votesArr.reverse(); // simple reverse array
    
    // re-assign
    for (let i = 0; i < c.options.length; i++) {
        c.options[i].sct_panel_votes = votesArr[i];
    }
  }
}

(async () => {
    console.log('Running analysis (pool size 10)...');
    await asyncPool(10, scts, processCase);
    
    console.log(`\nAnalysis complete.`);
    console.log(`Cases flipped: ${flippedCount}`);
    console.log(`Errors: ${errors}`);
    
    if (flippedCount > 0) {
        // Atomic save master
        writeFileSync(COMPILED_PATH + '.tmp', JSON.stringify(cases, null, 2));
        renameSync(COMPILED_PATH + '.tmp', COMPILED_PATH);
        
        // Save frontend
        const fc = cases.filter(c => !c.meta?.quarantined && !c.meta?.quarantine_flag);
        writeFileSync(FRONTEND_PATH + '.tmp', JSON.stringify(fc, null, 2));
        renameSync(FRONTEND_PATH + '.tmp', FRONTEND_PATH);
        
        console.log(`Saved updated compiled files!`);
    } else {
        console.log('No modifications needed.');
    }
})();
